+}
+
+#[test]
+fn proof_kind_ord() {
+    assert!(ProofKind::StaticAnalysis < ProofKind::DynamicAblation);
+    assert!(ProofKind::DynamicAblation < ProofKind::PolicyTheoremCheck);
+}
