+#[test]
+fn promotion_theorem_kind_display_builtins() {
+    assert_eq!(
+        PromotionTheoremKind::MergeLegality.to_string(),
+        "merge-legality"
+    );
+    assert_eq!(
+        PromotionTheoremKind::AttenuationLegality.to_string(),
+        "attenuation-legality"
+    );
