+        PromotionTheoremKind::MergeLegality,
+        PromotionTheoremKind::AttenuationLegality,
+        PromotionTheoremKind::NonInterference,
+        PromotionTheoremKind::Custom("foo".to_string()),
+    ];
+    for k in &kinds {
