+    assert_eq!(
+        synth.synthesis_count(),
+        count_after_first + cxs2.len() as u64 + cxs3.len() as u64
+    );
+    // Corpus should NOT grow because conflict_ids are the same.
+    assert_eq!(synth.corpus().len(), corpus_len_after_first + cxs2.len());
+}

