+// ── helpers ──────────────────────────────────────────────────────────────
+
+fn test_key() -> SigningKey {
+    SigningKey::from_bytes([42u8; 32])
+}
+
+fn sentinel_sig() -> Signature {
+    Signature::from_bytes(SIGNATURE_SENTINEL)
+}
+
+fn make_flow_policy() -> FlowPolicy {
+    FlowPolicy {
+        policy_id: "pol-001".into(),
+        extension_id: "ext-abc".into(),
