+        name: "beta".into(),
+        level: 3,
+    };
+    // Same level but different names → not equal
+    assert_ne!(a, b);
+    // can_flow_to is symmetric (both level 3)
+    assert!(a.can_flow_to(&b));
+    assert!(b.can_flow_to(&a));
