+#[test]
+fn store_apply_override_adds_temporary_root() {
+    let mut store = loaded_store(10);
+    let signer = sk();
+    let verifier = signer.verification_key();
+
+    let artifact = SignedTrustRootOverrideArtifact::create_signed(
+        &signer,
