+
+    cache
+        .get_or_generate(&generator, &graph, "ext-1", epoch, now)
+        .unwrap();
+
+    // Transition changes graph version.
+    graph
+        .transition_trust(
+            "ext-1",
+            TrustLevel::Provisional,
+            vec![],
